sql:
SELECT SUM(marketing_total) AS total_marketing_expenses
FROM marketing_channels
WHERE company_id = 1;

SELECT industry
FROM companies
WHERE company_id = 1;

SELECT company_id, SUM(marketing_total) AS total_marketing_expenses
FROM marketing_channels
GROUP BY company_id;

